-- OBD-II DTC lookup seed data
-- Common P0xxx codes per SAE J2012 standard. Prioritizes codes relevant to
-- tuned/modified vehicles: misfires, fuel trims, boost, knock, O2 sensors.

ON CONFLICT (code) DO UPDATE SET
  description = EXCLUDED.description,
  system = EXCLUDED.system,
  severity_hint = EXCLUDED.severity_hint,
  common_causes = EXCLUDED.common_causes;
